from functools import cache
@cache
def cfact2(n, j):
    if j == 0: return int(n == 0)
    if j < 1 or j > n: return 0
    return cfact2(n-1, j-1) + j * j * cfact2(n-1, j)
def T(n, j): return 1 if n == 0 else j*cfact2(n, j)
for n in range(10): print([T(n, j) for j in range(n + 1)])

